import { type Task } from 'wasp/entities';
import { type CreateAction } from 'wasp/server/crud/Tasks';

export const createTask: CreateAction = async (args, context) => {
  return context.entities.Task.create({
    data: {
      description: args.description + ' [NEW]',
      isDone: args.isDone || false
    }
  });
};

